from lxml import etree
import requests

def parse_soap_request(url, headers, body):
    parser = etree.XMLParser(dtd_validation=True)
    tree = etree.fromstring(body, parser=parser)
    envelope = tree.find("{http://schemas.xmlsoap.org/soap/envelope/}Body")

    if envelope is None:
        raise ValueError('Invalid SOAP envelope')
  
    return envelope

def send_soap_request(url, headers, body):
    response = requests.post(url, headers=headers, data=body)
    if response.status_code == 200:
        envelope = parse_soap_request(url, headers, response.text)
        return envelope
    else:
        print('SOAP request failed with status: ', response.status_code)